import { readFile, readdir, writeFile } from 'node:fs/promises';
import path from 'node:path';
import process from 'node:process';
import { fileURLToPath } from 'node:url';
import { icons as carbon } from '@iconify-json/carbon';
import { icons as healthicons } from '@iconify-json/healthicons';
import { icons as heroicons } from '@iconify-json/heroicons';
import { icons as lucide } from '@iconify-json/lucide';
import { icons as mdi } from '@iconify-json/mdi';
import { icons as solar } from '@iconify-json/solar';
import { getIcons } from '@iconify/utils';

const projectRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
const sourceRoot = path.join(projectRoot, 'resources/js');
const outputPath = path.join(sourceRoot, 'iconify-bundle.ts');
const collections = { carbon, healthicons, heroicons, lucide, mdi, solar };
const sourceExtensions = new Set(['.js', '.jsx', '.ts', '.tsx']);
const iconPattern = /(?:carbon|healthicons|heroicons|lucide|mdi|solar):[a-z0-9][a-z0-9-]*/g;

async function sourceFiles(directory) {
  const files = [];
  for (const entry of await readdir(directory, { withFileTypes: true })) {
    const target = path.join(directory, entry.name);
    if (entry.isDirectory()) files.push(...await sourceFiles(target));
    else if (sourceExtensions.has(path.extname(entry.name)) && target !== outputPath) files.push(target);
  }
  return files;
}

const requested = new Map(Object.keys(collections).map((prefix) => [prefix, new Set()]));
for (const file of await sourceFiles(sourceRoot)) {
  const contents = await readFile(file, 'utf8');
  for (const match of contents.matchAll(iconPattern)) {
    const [prefix, name] = match[0].split(':');
    requested.get(prefix).add(name);
  }
}

const subsets = [];
const iconNames = [];
for (const [prefix, collection] of Object.entries(collections)) {
  const names = [...requested.get(prefix)].sort();
  const subset = getIcons(collection, names, true);
  const missing = subset === null ? names : (subset.not_found ?? []);
  if (missing.length > 0) {
    throw new Error(`Missing local Iconify glyphs for ${prefix}: ${missing.join(', ')}`);
  }
  delete subset.not_found;
  subsets.push(subset);
  iconNames.push(...names.map((name) => `${prefix}:${name}`));
}

const generated = `/* This file is generated by scripts/build-iconify-bundle.mjs. */\n` +
  `import { addCollection, setCustomIconsLoader } from '@iconify/react';\n` +
  `import type { IconifyJSON } from '@iconify/types';\n\n` +
  `const collections: IconifyJSON[] = ${JSON.stringify(subsets, null, 2)};\n\n` +
  `export const localIconifyNames = ${JSON.stringify(iconNames.sort(), null, 2)} as const;\n\n` +
  `export function registerLocalIconifyCollections(): void {\n` +
  `  for (const collection of collections) {\n` +
  `    addCollection(collection);\n` +
  `    setCustomIconsLoader(() => null, collection.prefix);\n` +
  `  }\n` +
  `}\n`;

if (process.argv.includes('--check')) {
  const current = await readFile(outputPath, 'utf8').catch(() => '');
  if (current !== generated) {
    process.stderr.write('Local Iconify bundle is stale. Run npm run icons:build.\n');
    process.exitCode = 1;
  }
} else {
  await writeFile(outputPath, generated);
  process.stdout.write(`Wrote ${path.relative(projectRoot, outputPath)} with ${iconNames.length} local icons.\n`);
}
